def two_sum(nums, target):
    for i in range(len(nums)):
        for j in range(i + 1, len(nums)):
            if nums[i] + nums[j] == target:
                return [i, j]
    return []

def is_valid(s):
    while "()" in s or "{}" in s or "[]" in s:
        s = s.replace("()", "").replace("{}", "").replace("[]", "")
    return s == ""

def max_area(height):
    max_water = 0
    for i in range(len(height)):
        for j in range(i + 1, len(height)):
            max_water = max(max_water, min(height[i], height[j]) * (j - i))
    return max_water

def length_of_longest_substring(s):
    def check(start, end):
        chars = set()
        for i in range(start, end + 1):
            if s[i] in chars:
                return False
            chars.add(s[i])
        return True
    res = 0
    for i in range(len(s)):
        for j in range(i, len(s)):
            if check(i, j):
                res = max(res, j - i + 1)
    return res

def group_anagrams(strs):
    groups = []
    for s in strs:
        found = False
        for group in groups:
            if sorted(group[0]) == sorted(s):
                group.append(s)
                found = True
                break
        if not found:
            groups.append([s])
    return groups

def product_except_self(nums):
    ans = []
    for i in range(len(nums)):
        prod = 1
        for j in range(len(nums)):
            if i != j:
                prod *= nums[j]
        ans.append(prod)
    return ans

def subarray_sum(nums, k):
    count = 0
    for i in range(len(nums)):
        curr_sum = 0
        for j in range(i, len(nums)):
            curr_sum += nums[j]
            if curr_sum == k:
                count += 1
    return count

def num_islands(grid):
    islands = 0
    visited = set()
    for r in range(len(grid)):
        for c in range(len(grid[0])):
            if grid[r][c] == '1' and (r, c) not in visited:
                islands += 1
                queue = [(r, c)]
                while queue:
                    curr_r, curr_c = queue.pop(0)
                    if (curr_r, curr_c) not in visited:
                        visited.add((curr_r, curr_c))
                        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                            nr, nc = curr_r + dr, curr_c + dc
                            if 0<=nr<len(grid) and 0<=nc<len(grid[0]) and grid[nr][nc]=='1':
                                queue.append((nr, nc))
    return islands

def merge(intervals):
    merged = []
    for interval in intervals:
        overlap = False
        for m in merged:
            if max(interval[0], m[0]) <= min(interval[1], m[1]):
                m[0] = min(interval[0], m[0])
                m[1] = max(interval[1], m[1])
                overlap = True
                break
        if not overlap:
            merged.append(interval)
    return merged

def coin_change(coins, amount):
    def dfs(rem):
        if rem == 0: return 0
        if rem < 0: return float('inf')
        res = float('inf')
        for coin in coins:
            res = min(res, 1 + dfs(rem - coin))
        return res
    ans = dfs(amount)
    return ans if ans != float('inf') else -1

def length_of_lis(nums):
    def solve(curr, prev_idx):
        if curr == len(nums): return 0
        take = 0
        if prev_idx == -1 or nums[curr] > nums[prev_idx]:
            take = 1 + solve(curr + 1, curr)
        skip = solve(curr + 1, prev_idx)
        return max(take, skip)
    return solve(0, -1)

def min_distance(word1, word2):
    def solve(i, j):
        if i == len(word1): return len(word2) - j
        if j == len(word2): return len(word1) - i
        if word1[i] == word2[j]: return solve(i + 1, j + 1)
        return 1 + min(solve(i+1, j), solve(i, j+1), solve(i+1, j+1))
    return solve(0, 0)

def find_duplicate(nums):
    for i in range(len(nums)):
        for j in range(i + 1, len(nums)):
            if nums[i] == nums[j]:
                return nums[i]
